(138, 37, 'workout_reminder', '⏰ MyFitCal — You missed your 12:23 PM workout, Silagan!', '<!DOCTYPE html>\r\n<html>\r\n<head><meta charset=\"UTF-8\"></head>\r\n<body style=\"margin:0;padding:0;background:#f0f4f8;font-family:\'Segoe UI\',Arial,sans-serif;\">\r\n<table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#f0f4f8;padding:32px 16px;\">\r\n<tr><td align=\"center\">\r\n<table width=\"560\" cellpadding=\"0\" cellspacing=\"0\" style=\"max-width:560px;width:100%;\">\r\n  <tr><td style=\"background:linear-gradient(135deg,#0a1628,#0d2137,#0a2e1f);border-radius:20px 20px 0 0;padding:32px;text-align:center;\">\r\n    <div style=\"display:inline-block;background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.15);border-radius:999px;padding:6px 18px;font-size:11px;font-weight:700;color:rgba(255,255,255,.6);letter-spacing:1px;text-transform:uppercase;margin-bottom:16px;\">⏰ Missed Workout Reminder</div>\r\n    <h1 style=\"margin:0;font-size:26px;color:#fff;font-weight:900;\">Hey Silagan!</h1>\r\n    <p style=\"margin:10px 0 0;font-size:14px;color:rgba(255,255,255,.5);\">Your 12:23 PM workout reminder passed — don\'t skip today!</p>\r\n  </td></tr>\r\n  <tr><td style=\"background:#fff;padding:32px;\">\r\n    <div style=\"background:#fff7ed;border:1.5px solid #fed7aa;border-radius:14px;padding:14px 18px;margin-bottom:24px;\">\r\n      <div style=\"font-size:13px;font-weight:800;color:#c2410c;\">⚠️ Don\'t skip today\'s workout!</div>\r\n      <div style=\"font-size:12px;color:#ea580c;margin-top:4px;\">You set a reminder at 12:23 PM but haven\'t started yet. It\'s not too late!</div>\r\n    </div>\r\n    <div style=\"text-align:center;margin-bottom:24px;\">\r\n      <div style=\"display:inline-block;background:#16a34a18;border:2px solid #16a34a44;border-radius:16px;padding:16px 36px;\">\r\n        <div style=\"font-size:48px;font-weight:900;color:#16a34a;line-height:1;\">Day 9</div>\r\n        <div style=\"font-size:12px;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:1px;margin-top:6px;\">of 30 Days</div>\r\n      </div>\r\n    </div>\r\n    <p style=\"margin:0 0 8px;font-size:12px;font-weight:700;color:#64748b;text-transform:uppercase;\">Your Progress</p>\r\n    <div style=\"background:#f1f5f9;border-radius:999px;height:10px;overflow:hidden;margin-bottom:6px;\">\r\n      <div style=\"background:#16a34a;height:100%;width:27%;border-radius:999px;\"></div>\r\n    </div>\r\n    <div style=\"display:flex;justify-content:space-between;font-size:12px;color:#64748b;margin-bottom:24px;\">\r\n      <span>8 / 30 days done</span><span>27% complete</span>\r\n    </div>\r\n    <table width=\"100%\" cellpadding=\"4\" cellspacing=\"0\" style=\"margin-bottom:24px;\">\r\n      <tr>\r\n        <td width=\"33%\"><div style=\"background:#f8fafc;border-radius:12px;padding:14px;text-align:center;\"><div style=\"font-size:22px;font-weight:900;color:#0f172a;\">8</div><div style=\"font-size:10px;font-weight:700;color:#94a3b8;text-transform:uppercase;margin-top:2px;\">Done</div></div></td>\r\n        <td width=\"33%\"><div style=\"background:#f8fafc;border-radius:12px;padding:14px;text-align:center;\"><div style=\"font-size:22px;font-weight:900;color:#16a34a;\">22</div><div style=\"font-size:10px;font-weight:700;color:#94a3b8;text-transform:uppercase;margin-top:2px;\">Remaining</div></div></td>\r\n        <td width=\"33%\"><div style=\"background:#f8fafc;border-radius:12px;padding:14px;text-align:center;\"><div style=\"font-size:22px;font-weight:900;color:#0f172a;\">30</div><div style=\"font-size:10px;font-weight:700;color:#94a3b8;text-transform:uppercase;margin-top:2px;\">Total</div></div></td>\r\n      </tr>\r\n    </table>\r\n    <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background:#f8fafc;border-radius:14px;margin-bottom:24px;\">\r\n      <tr>\r\n        <td style=\"padding:14px 20px;\"><div style=\"font-size:10px;font-weight:700;color:#94a3b8;text-transform:uppercase;margin-bottom:3px;\">Goal</div><div style=\"font-size:14px;font-weight:800;color:#0f172a;\">Weight Loss</div></td>\r\n        <td style=\"padding:14px 20px;border-left:1px solid #e2e8f0;\"><div style=\"font-size:10px;font-weight:700;color:#94a3b8;text-transform:uppercase;margin-bottom:3px;\">Level</div><div style=\"font-size:14px;font-weight:800;color:#0f172a;\">Expert</div></td>\r\n      </tr>\r\n    </table>\r\n    <div style=\"text-align:center;margin-bottom:20px;\">\r\n      <a href=\"http://localhost/myfitcal_system/user/workout.php?day=9\" style=\"display:inline-block;background:#16a34a;color:#fff;text-decoration:none;font-size:15px;font-weight:800;padding:14px 40px;border-radius:12px;\">\r\n        Start Day 9 Workout Now →\r\n      </a>\r\n    </div>\r\n    <p style=\"margin:0;font-size:13px;color:#94a3b8;text-align:center;line-height:1.7;\">\r\n      Even a late workout is better than none!<br>\r\n      <strong style=\"color:#0f172a;\">MyFitCal</strong> believes in you 💪\r\n    </p>\r\n  </td></tr>\r\n  <tr><td style=\"background:#f8fafc;border-radius:0 0 20px 20px;padding:18px;text-align:center;\">\r\n    <p style=\"margin:0;font-size:11px;color:#94a3b8;\">MyFitCal · You set a reminder at 12:23 PM</p>\r\n  </td></tr>\r\n</table>\r\n</td></tr>\r\n</table>\r\n</body>\r\n</html>', 'cuarterosjames11@gmail.com', 'sent', '2026-04-24 18:32:46', '2026-04-24 18:32:46');
