-- --------------------------------------------------------

--
-- Table structure for table `fitness_activities`
--

CREATE TABLE `fitness_activities` (
  `id` int(10) UNSIGNED NOT NULL,
  `user_id` int(10) UNSIGNED NOT NULL,
  `activity_type` varchar(80) NOT NULL,
  `duration_min` int(11) DEFAULT NULL,
  `calories_burned` int(11) DEFAULT NULL,
  `activity_date` date NOT NULL DEFAULT curdate(),
  `notes` text DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- --------------------------------------------------------

--
-- Table structure for table `meal_compliance`
--

CREATE TABLE `meal_compliance` (
  `id` int(10) UNSIGNED NOT NULL,
  `user_id` int(10) UNSIGNED NOT NULL,
  `log_date` date NOT NULL,
  `day_number` int(11) NOT NULL DEFAULT 1,
  `total_foods` int(11) NOT NULL DEFAULT 0,
  `checked_foods` int(11) NOT NULL DEFAULT 0,
  `is_complete` tinyint(1) DEFAULT 0,
  `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

